import{_ as p,C as c,o as s,c as d,a2 as n,b as o,w as a,a as l,E as i,a3 as r}from"./chunks/framework.B72_uj9U.js";const A=JSON.parse('{"title":"Aider — Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/aider/context-management.md","filePath":"research/agents/aider/context-management.md"}'),h={name:"research/agents/aider/context-management.md"};function m(u,e,y,g,f,b){const t=c("Mermaid");return s(),d("div",null,[e[2]||(e[2]=n('<h1 id="aider-—-context-management" tabindex="-1">Aider — Context Management <a class="header-anchor" href="#aider-—-context-management" aria-label="Permalink to &quot;Aider — Context Management&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Context management is one of Aider&#39;s strongest technical contributions. The challenge: LLMs have finite context windows, but real codebases have thousands of files. Aider solves this with a multi-layered context strategy centered on the <strong>repo-map</strong> — a tree-sitter-powered, graph-ranked summary of the entire codebase.</p><h2 id="the-three-layers-of-context" tabindex="-1">The Three Layers of Context <a class="header-anchor" href="#the-three-layers-of-context" aria-label="Permalink to &quot;The Three Layers of Context&quot;">​</a></h2>',4)),(s(),o(r,null,{default:a(()=>[i(t,{id:"mermaid-12",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20L1%5B%22Layer%201%3A%20Added%20Files%20%E2%80%94%20full%20content%5CnFiles%20explicitly%20%2Fadd'd%20to%20the%20chat%5CnEditable%20by%20the%20LLM%20%C2%B7%20highest%20token%20cost%2C%20highest%20fidelity%22%5D%0A%20%20%20%20L2%5B%22Layer%202%3A%20Repo%20Map%20%E2%80%94%20ranked%20summary%5CnTree-sitter%20extracted%20symbols%20from%20ALL%20files%5CnGraph-ranked%20by%20importance%2Frelevance%5CnToken-budgeted%20to%20fit%20available%20context%22%5D%0A%20%20%20%20L3%5B%22Layer%203%3A%20Chat%20History%5CnPrevious%20conversation%20messages%5CnSummarized%20when%20too%20long%22%5D%0A%0A%20%20%20%20L1%20--%3E%20L2%20--%3E%20L3%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=n(`<h2 id="repo-map-deep-dive" tabindex="-1">Repo-Map: Deep Dive <a class="header-anchor" href="#repo-map-deep-dive" aria-label="Permalink to &quot;Repo-Map: Deep Dive&quot;">​</a></h2><h3 id="what-it-is" tabindex="-1">What It Is <a class="header-anchor" href="#what-it-is" aria-label="Permalink to &quot;What It Is&quot;">​</a></h3><p>The repo-map is a <strong>concise structural summary</strong> of the entire git repository. It shows:</p><ul><li>File paths</li><li>Class definitions (names, inheritance)</li><li>Function/method signatures (names, parameters, types)</li><li>Key variable declarations</li><li>Import relationships</li></ul><p>But critically, it does <strong>not</strong> show:</p><ul><li>Function bodies / implementation details</li><li>Comments</li><li>Most variable assignments</li><li>Test code internals</li></ul><h3 id="how-it-s-built" tabindex="-1">How It&#39;s Built <a class="header-anchor" href="#how-it-s-built" aria-label="Permalink to &quot;How It&#39;s Built&quot;">​</a></h3><h4 id="step-1-tree-sitter-parsing" tabindex="-1">Step 1: Tree-Sitter Parsing <a class="header-anchor" href="#step-1-tree-sitter-parsing" aria-label="Permalink to &quot;Step 1: Tree-Sitter Parsing&quot;">​</a></h4><p>Aider uses <a href="https://tree-sitter.github.io/tree-sitter/" target="_blank" rel="noreferrer">tree-sitter</a> to parse every source file into an Abstract Syntax Tree (AST). Tree-sitter is the same parsing library used by many IDEs for syntax highlighting, code folding, and navigation.</p><p>For each file, aider extracts:</p><ul><li><strong>Definitions</strong>: Where symbols (functions, classes, variables) are defined</li><li><strong>References</strong>: Where symbols from other files are used</li></ul><p>This is done using custom <code>.scm</code> (Scheme) query files in <code>aider/queries/</code>, one per language:</p><ul><li><code>tree-sitter-python-tags.scm</code></li><li><code>tree-sitter-javascript-tags.scm</code></li><li><code>tree-sitter-rust-tags.scm</code></li><li>... (supports 100+ languages)</li></ul><h4 id="step-2-dependency-graph-construction" tabindex="-1">Step 2: Dependency Graph Construction <a class="header-anchor" href="#step-2-dependency-graph-construction" aria-label="Permalink to &quot;Step 2: Dependency Graph Construction&quot;">​</a></h4><p>From the definitions and references, aider builds a <strong>file-level dependency graph</strong>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Node = source file</span></span>
<span class="line"><span>Edge = file A references a symbol defined in file B</span></span></code></pre></div><p>For example:</p>`,17)),(s(),o(r,null,{default:a(()=>[i(t,{id:"mermaid-133",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20app%5B%22app.py%22%5D%0A%20%20%20%20models%5B%22models.py%22%5D%0A%20%20%20%20utils%5B%22utils.py%22%5D%0A%20%20%20%20tests%5B%22tests%2Ftest_app.py%22%5D%0A%0A%20%20%20%20app%20--%3E%7C%22references%20(User%20class)%22%7C%20models%0A%20%20%20%20app%20--%3E%7C%22references%20(validate_email)%22%7C%20utils%0A%20%20%20%20tests%20--%3E%7C%22references%20(tests%20endpoints)%22%7C%20app%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[l(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=n(`<h4 id="step-3-graph-ranking-pagerank-style" tabindex="-1">Step 3: Graph Ranking (PageRank-style) <a class="header-anchor" href="#step-3-graph-ranking-pagerank-style" aria-label="Permalink to &quot;Step 3: Graph Ranking (PageRank-style)&quot;">​</a></h4><p>Aider uses a <strong>personalized PageRank</strong> algorithm on this dependency graph to determine which files and symbols are most important. The ranking is &quot;personalized&quot; — biased toward:</p><ol><li><strong>Files currently in the chat</strong> — symbols referenced by added files rank higher</li><li><strong>Mentioned identifiers</strong> — if the user mentions a class or function name, files containing that symbol rank higher</li><li><strong>Recently discussed files</strong> — context from the conversation influences ranking</li></ol><p>This is implemented in <code>repomap.py</code> using a graph algorithm similar to Google&#39;s PageRank, adapted for code structure.</p><h4 id="step-4-token-budgeted-selection" tabindex="-1">Step 4: Token-Budgeted Selection <a class="header-anchor" href="#step-4-token-budgeted-selection" aria-label="Permalink to &quot;Step 4: Token-Budgeted Selection&quot;">​</a></h4><p>The ranked symbols are selected to fit within the <strong>token budget</strong> (<code>--map-tokens</code>, default 1024 tokens):</p><ol><li>Start with the highest-ranked symbols</li><li>For each symbol, include the &quot;key lines&quot; — the definition signature, class declaration, etc.</li><li>Use <code>TreeContext</code> (from <code>grep_ast</code>) to format the output with contextual &quot;elision&quot; markers (<code>⋮...</code>)</li><li>Keep adding symbols until the token budget is consumed</li></ol><h4 id="step-5-dynamic-sizing" tabindex="-1">Step 5: Dynamic Sizing <a class="header-anchor" href="#step-5-dynamic-sizing" aria-label="Permalink to &quot;Step 5: Dynamic Sizing&quot;">​</a></h4><p>The repo map size is <strong>not static</strong> — it adjusts based on the conversation state:</p><ul><li><strong>No files added</strong>: Map expands significantly (up to <code>map_mul_no_files × map_tokens</code>, default 8×) because the LLM needs maximum codebase awareness</li><li><strong>Files added</strong>: Map shrinks to leave room for file content</li><li><strong>Long conversation</strong>: Map shrinks to leave room for chat history</li><li><strong>The map never exceeds what fits</strong> — aider calculates available tokens dynamically</li></ul><h3 id="what-the-map-looks-like" tabindex="-1">What the Map Looks Like <a class="header-anchor" href="#what-the-map-looks-like" aria-label="Permalink to &quot;What the Map Looks Like&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>aider/coders/base_coder.py:</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│class Coder:</span></span>
<span class="line"><span>│    abs_fnames = None</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│    @classmethod</span></span>
<span class="line"><span>│    def create(</span></span>
<span class="line"><span>│        self,</span></span>
<span class="line"><span>│        main_model,</span></span>
<span class="line"><span>│        edit_format,</span></span>
<span class="line"><span>│        io,</span></span>
<span class="line"><span>│        skip_model_availabily_check=False,</span></span>
<span class="line"><span>│        **kwargs,</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│    def abs_root_path(self, path):</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│    def run(self, with_message=None):</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>aider/commands.py:</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│class Commands:</span></span>
<span class="line"><span>│    voice = None</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│    def get_commands(self):</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│    def run(self, inp):</span></span>
<span class="line"><span>⋮...</span></span></code></pre></div><p>The <code>⋮...</code> markers indicate elided code. The <code>│</code> markers show the indentation level. This compact format conveys the structure without wasting tokens on implementation.</p><h3 id="caching" tabindex="-1">Caching <a class="header-anchor" href="#caching" aria-label="Permalink to &quot;Caching&quot;">​</a></h3><p>The repo map uses multiple caching layers for performance:</p><ol><li><strong>Tags cache</strong> — Tree-sitter parse results are cached to disk (<code>.aider.tags.cache.v4/</code>)</li><li><strong>Tree context cache</strong> — Formatted output is cached in memory</li><li><strong>Map cache</strong> — The fully assembled map is cached, keyed on the set of chat files + mentioned identifiers</li><li><strong>Refresh modes</strong>: <ul><li><code>auto</code> (default) — Refresh when files change</li><li><code>always</code> — Rebuild every time</li><li><code>manual</code> — Only refresh on <code>/map-refresh</code></li></ul></li></ol><h2 id="file-selection-manual-vs-assisted" tabindex="-1">File Selection: Manual vs. Assisted <a class="header-anchor" href="#file-selection-manual-vs-assisted" aria-label="Permalink to &quot;File Selection: Manual vs. Assisted&quot;">​</a></h2><h3 id="manual-selection" tabindex="-1">Manual Selection <a class="header-anchor" href="#manual-selection" aria-label="Permalink to &quot;Manual Selection&quot;">​</a></h3><p>Users explicitly add files with <code>/add</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>/add src/auth/login.py src/models/user.py</span></span></code></pre></div><p>The repo map helps here — the LLM can see the structure of the entire codebase and ask for specific files:</p><blockquote><p>&quot;I need to see <code>src/utils/validation.py</code> to understand how validation works. Can you add it?&quot;</p></blockquote><p>Aider will then prompt the user to add the requested file.</p><h3 id="watch-mode-semi-automatic" tabindex="-1">Watch Mode (Semi-Automatic) <a class="header-anchor" href="#watch-mode-semi-automatic" aria-label="Permalink to &quot;Watch Mode (Semi-Automatic)&quot;">​</a></h3><p>With <code>--watch-files</code>, adding an <code># AI</code> comment to any file automatically adds it to the chat context.</p><h3 id="mentioned-file-detection" tabindex="-1">Mentioned File Detection <a class="header-anchor" href="#mentioned-file-detection" aria-label="Permalink to &quot;Mentioned File Detection&quot;">​</a></h3><p>Aider automatically detects when the LLM mentions file paths in its response and can suggest adding them.</p><h2 id="token-budget-management" tabindex="-1">Token Budget Management <a class="header-anchor" href="#token-budget-management" aria-label="Permalink to &quot;Token Budget Management&quot;">​</a></h2><p>Aider carefully manages the available context window:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Total Context Window (e.g., 128k tokens)</span></span>
<span class="line"><span>├── System prompt + edit format instructions (~1-2k)</span></span>
<span class="line"><span>├── Repo map (dynamic, default budget: 1k, expandable to 8k)</span></span>
<span class="line"><span>├── Added files (full content)</span></span>
<span class="line"><span>├── Read-only files (full content)</span></span>
<span class="line"><span>├── Chat history (dynamic, summarized when too long)</span></span>
<span class="line"><span>├── Current user message</span></span>
<span class="line"><span>└── Reserved for LLM response (~4k minimum)</span></span></code></pre></div><h3 id="token-counting" tabindex="-1">Token Counting <a class="header-anchor" href="#token-counting" aria-label="Permalink to &quot;Token Counting&quot;">​</a></h3><p>Aider counts tokens using the model&#39;s actual tokenizer when messages are short. For longer texts, it uses a <strong>sampling-based estimation</strong> for efficiency:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> token_count</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> text</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> &lt;</span><span style="color:#FAB387;"> 200</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">main_model</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">token_count</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Sample every 100th line, extrapolate</span></span>
<span class="line"><span style="color:#CDD6F4;">    lines </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> text</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">splitlines</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">keepends</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    step </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">lines</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> //</span><span style="color:#FAB387;"> 100</span><span style="color:#CBA6F7;"> or</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"><span style="color:#CDD6F4;">    sample </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> lines</span><span style="color:#9399B2;">[::</span><span style="color:#EBA0AC;font-style:italic;">step</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">    sample_tokens </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">main_model</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">token_count</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;&quot;</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">join</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">sample</span><span style="color:#9399B2;">))</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> sample_tokens </span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;&quot;</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">join</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">sample</span><span style="color:#9399B2;">))</span><span style="color:#94E2D5;"> *</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">)</span></span></code></pre></div><h3 id="history-summarization" tabindex="-1">History Summarization <a class="header-anchor" href="#history-summarization" aria-label="Permalink to &quot;History Summarization&quot;">​</a></h3><p>When conversation history grows too large, aider can summarize older messages to reclaim context space. This keeps the most recent and most relevant context while compressing earlier discussion.</p><h2 id="comparison-to-other-tools" tabindex="-1">Comparison to Other Tools <a class="header-anchor" href="#comparison-to-other-tools" aria-label="Permalink to &quot;Comparison to Other Tools&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Aider</th><th>Claude Code</th><th>Cursor</th><th>Copilot</th></tr></thead><tbody><tr><td><strong>Codebase awareness</strong></td><td>Repo-map (tree-sitter + PageRank)</td><td>Tool calls to read files</td><td>Embeddings index</td><td>Line-level context</td></tr><tr><td><strong>Automatic context</strong></td><td>Repo-map auto-ranks</td><td>Agent decides what to read</td><td>RAG retrieval</td><td>Immediate context</td></tr><tr><td><strong>Manual control</strong></td><td>/add, /drop</td><td>Agent handles it</td><td>@file mentions</td><td>None</td></tr><tr><td><strong>Token efficiency</strong></td><td>Ranked symbol extraction</td><td>Full file reads</td><td>Chunk-based</td><td>Line windows</td></tr><tr><td><strong>Language support</strong></td><td>100+ via tree-sitter</td><td>All (reads raw text)</td><td>Many</td><td>Many</td></tr></tbody></table><p>The repo-map approach is uniquely <strong>proactive</strong> — it gives the LLM awareness of the full codebase structure before it even asks. This is in contrast to agent-based approaches where the model must explicitly request files, potentially missing relevant context it didn&#39;t know existed.</p>`,38))])}const C=p(h,[["render",m]]);export{A as __pageData,C as default};
